#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
inline int read()
{
    int res=0;char ch=getchar();bool flag=0;
    while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
    while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
    return flag ? -res : res ;
}
inline void Solve()
{
    int k=read(),a=read(),b=read();if(a>b){int tmp=a;a=b;b=tmp;}
    putchar(((a%(k+1)==0)||(b-a+a/(k+1)*(k!=1))&1)?'+':'-');puts("");
}
int main()
{
    int T=read();while(T--)Solve();return 0;
}
